// 展示Scalar单元在程序控制中的作用
template<typename T>
class ScalarControlKernel {
public:
void Compute(Tensor input, Tensor output, int iterations) {
// 使用Scalar单元进行循环控制和地址计算
for (int i = 0; i < iterations; i++) {
// Scalar单元计算地址偏移
int offset = i * block_size;

...

